import{_ as e,o as a,c as l,ag as i}from"./chunks/framework-C5-Jzrz4.js";const t=JSON.parse('{"title":"常见问题解决方案","description":"基于当前源码注释和实现整理的常见问题与处理方式","frontmatter":{"title":"常见问题解决方案","description":"基于当前源码注释和实现整理的常见问题与处理方式"},"headers":[],"relativePath":"scripts/guide/07-常见问题解决方案.md","filePath":"scripts/guide/07-常见问题解决方案.md","lastUpdated":null}');const o=e({name:"scripts/guide/07-常见问题解决方案.md"},[["render",function(e,t,o,r,d,c){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="常见问题解决方案" tabindex="-1">常见问题解决方案 <a class="header-anchor" href="#常见问题解决方案" aria-label="Permalink to &quot;常见问题解决方案&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>以下问题来自当前仓库源码注释、实现逻辑与已存在行为，不包含推测性结论。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>登录与权限异常</li><li>请求与加密异常</li><li>字典与表单展示异常</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/utils/http/index.ts</code></li><li><code>apps/web-antd/src/utils/http/helper.ts</code></li><li><code>apps/web-antd/src/store/dict.ts</code></li><li><code>apps/web-antd/src/preferences.ts</code></li><li><code>apps/web-antd/src/adapter/component/index.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="_1-sm2-rsa-加密问题" tabindex="-1">1. SM2/RSA 加密问题 <a class="header-anchor" href="#_1-sm2-rsa-加密问题" aria-label="Permalink to &quot;1. SM2/RSA 加密问题&quot;">​</a></h3><ul><li>当前实现默认 <code>RsaEncryption + AesEncryption</code>。</li><li>源码注释已明确：前端 <code>sm-crypto</code> 场景下公钥需 <code>04</code> 开头，否则可能失败。</li><li><code>axios</code> 对字符串包引号的问题已通过 <code>transformRequest</code> 处理。</li></ul><h3 id="_2-微服务网关-401-兼容问题" tabindex="-1">2. 微服务网关 401 兼容问题 <a class="header-anchor" href="#_2-微服务网关-401-兼容问题" aria-label="Permalink to &quot;2. 微服务网关 401 兼容问题&quot;">​</a></h3><ul><li>源码注释指出：网关若返回 <code>text/plain</code>，JSON 分支逻辑不会生效。</li><li>当前策略偏向后端网关修正，而不是在前端增加复杂兼容分支。</li></ul><h3 id="_3-字典重复请求" tabindex="-1">3. 字典重复请求 <a class="header-anchor" href="#_3-字典重复请求" aria-label="Permalink to &quot;3. 字典重复请求&quot;">​</a></h3><ul><li><code>useDictStore</code> 使用 <code>dictRequestCache</code> 对同名字典请求加锁，避免页面多处重复并发。</li></ul><h3 id="_4-keepalive-语言切换下-placeholder-不更新" tabindex="-1">4. KeepAlive + 语言切换下 placeholder 不更新 <a class="header-anchor" href="#_4-keepalive-语言切换下-placeholder-不更新" aria-label="Permalink to &quot;4. KeepAlive + 语言切换下 placeholder 不更新&quot;">​</a></h3><ul><li>组件适配层使用计算属性生成 placeholder，避免缓存场景展示不刷新。</li></ul><h3 id="_5-数组参数和区间参数传递异常" tabindex="-1">5. 数组参数和区间参数传递异常 <a class="header-anchor" href="#_5-数组参数和区间参数传递异常" aria-label="Permalink to &quot;5. 数组参数和区间参数传递异常&quot;">​</a></h3><ul><li>GET/DELETE 默认启用 <code>paramsSerializer</code>，数组采用 <code>repeat</code> 格式，解决后端参数接收问题。</li></ul><h3 id="_6-登录过期弹窗模式限制" tabindex="-1">6. 登录过期弹窗模式限制 <a class="header-anchor" href="#_6-登录过期弹窗模式限制" aria-label="Permalink to &quot;6. 登录过期弹窗模式限制&quot;">​</a></h3><ul><li><code>preferences.ts</code> 注释明确：当前不启用 modal 形式的登录过期处理，避免菜单与页面状态不一致。</li></ul><h3 id="_7-clientid-绑定异常" tabindex="-1">7. ClientID 绑定异常 <a class="header-anchor" href="#_7-clientid-绑定异常" aria-label="Permalink to &quot;7. ClientID 绑定异常&quot;">​</a></h3><ul><li>HTTP 封装注释已记录：<code>ClientID</code> 头在部分后端场景可能被错误绑定到实体类。</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>排障优先查看浏览器 Network 与 <code>utils/http</code> 中实际 header/body。</li><li>请求异常时先确认环境变量和代理，再检查 token/语言头/加密开关。</li><li>若需扩展故障处理策略，优先在 <code>utils/http/*</code> 做集中改造。</li></ul>',24)])])}]]);export{t as __pageData,o as default};
